import React, { useState } from 'react';

const App = () => {
  const [message, setMessage] = useState('');
  const [chatLog, setChatLog] = useState([]);

  const handleSendMessage = () => {
    setChatLog([...chatLog, { text: message, userId: 1 }]);
    setMessage('');
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] rounded-lg p-4 w-full">
        <div className="h-20 bg-[#411C56] text-white p-2 rounded-t-lg">
          <h1 className="text-lg font-bold">Chat Log</h1>
        </div>
        <div className="h-200 overflow-y-scroll p-2">
          {chatLog.map((log, index) => (
            <div key={index} className="bg-[#B7D7CD] p-2 mb-2 rounded-lg">
              <p>{log.text}</p>
            </div>
          ))}
        </div>
        <div className="h-20 bg-[#411C56] text-white p-2 rounded-b-lg">
          <input
            type="text"
            className="w-full p-2 rounded-lg bg-transparent text-white"
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            onKeyPress={(e) => {
              if (e.key === "Enter") handleSendMessage();
            }}
          />
          <button className="bg-[#B7D7CD] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded">
            Send
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;
